import{_ as r,o as n,c as s,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"79. Requests For Flexible Working Arrangements","description":"","frontmatter":{"title":"79. Requests For Flexible Working Arrangements","eba":"Health Allied & Managers Admin 2021-2025","topics":["flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/classification-staffing/79-requests-for-flexible-working-arrangements.md","filePath":"ebas/has-managers-admin/common-terms/classification-staffing/79-requests-for-flexible-working-arrangements.md"}'),o={name:"ebas/has-managers-admin/common-terms/classification-staffing/79-requests-for-flexible-working-arrangements.md"};function a(i,e,g,m,l,p){return n(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="_79-requests-for-flexible-working-arrangements" tabindex="-1">79. Requests For Flexible Working Arrangements <a class="header-anchor" href="#_79-requests-for-flexible-working-arrangements" aria-label="Permalink to &quot;79. Requests For Flexible Working Arrangements&quot;">​</a></h1><p><strong>79.1</strong> If any of the circumstances set out in subclause 79.2 below apply to an Employee, the Employee may ask the Employer for a change in working arrangements because of those circumstances:</p><p><strong>79.2</strong> The Employee</p><p><strong>(a)</strong> is the parent, or has responsibility for the care, of a child who is of school age or younger;</p><p><strong>(b)</strong> is a carer (within the meaning of the Carer Recognition Act 2010);</p><p><strong>(c)</strong> has a disability;</p><p><strong>(d)</strong> is 55 or older;</p><p><strong>(e)</strong> is experiencing violence from a member of the Employee’s family; or</p><p><strong>(f)</strong> provides care or support to a member of the Employee’s immediate family, or a member of the member of the Employee’s household, who requires care or support because the member is experiencing violence from the member’s family.</p><p><strong>79.3</strong> A request made under subclause 79.1 may include, but is not limited to, changes in hours of work, changes in patterns of work or changes in the location of work.</p><p><strong>79.4</strong> An Employee is not entitled to make a request under subclause 79.1 unless:</p><p><strong>(a)</strong> for an Employee, other than a casual Employee, they have completed at least 12 months continuous service with the Employer immediately before making the request; or</p><p><strong>(b)</strong> for a casual Employee, they have:</p><p><strong>(i)</strong> been engaged by the Employer on a regular and systematic basis for a sequence of periods of employment during a period of at least 12 months immediately before making the request; and</p><p><strong>(ii)</strong> have a reasonable expectation of continuing engagement by the Employer on a regular and systematic basis.</p><p><strong>79.5</strong> A request made under subclause 79.1 must be in writing and set out:</p><p><strong>(a)</strong> details of the change in working arrangements sought by the Employee; and</p><p><strong>(b)</strong> the reasons for the change.</p><p><strong>79.6</strong> Before responding to a request made under subclause 79.1, the Employer must discuss the request with the Employee and genuinely try to reach agreement on a change in working arrangements that will reasonably accommodate the Employee’s circumstances having regard to:</p><p><strong>(a)</strong> the needs of the Employee arising from their circumstances;</p><p><strong>(b)</strong> the consequences for the Employee if changes in working arrangements are not made; and</p><p><strong>(c)</strong> any reasonable grounds for refusing the request.</p><p><strong>79.7</strong> The Employer must respond to a request made under subclause 79.1 within 21 days, stating whether or not the request is granted.</p><p><strong>79.8</strong> The Employer may refuse a request made under subclause 79.1 on reasonable business grounds.</p><p><strong>79.9</strong> If the Employer refuses a request made by an Employee under clause 79.1, or if the change in working arrangements differs from that initially requested by the employee, the written response provided under subclause 79.7 must include the reasons for such a refusal, including the business ground or grounds for the refusal and how the ground or grounds apply.</p><p><strong>79.10</strong> If the Employer and Employee could not agree on a change in working arrangements under subclause 79.6, then the written response under subclause 79.7 must:</p><p><strong>(a)</strong> state whether or not there are any changes in working arrangements that the Employer can offer the Employee so as to better accommodate the Employee’s circumstances; and</p><p><strong>(b)</strong> if the Employer can offer the Employee such changes in working arrangements, set out those changes in working arrangements.</p><p>PART J – OCCUPATIONAL HEALTH AND SAFETY AND RELATED MATTERS</p><p>Plain language terms: flex work, flexible hours, work from home, WFH.</p>',30)])])}const c=r(o,[["render",a]]);export{h as __pageData,c as default};
